export interface AdminUser {
  username: string;
  password: string;
}

export enum AttendanceStatus {
  CLOCKED_IN = 'CLOCKED_IN',
  CLOCKED_OUT = 'CLOCKED_OUT'
}

export type StaffStatus = 'PENDING' | 'INTERVIEWED' | 'ACTIVE' | 'REJECTED';

export type QueueStatus = 'WAITING' | 'CALLED' | 'COMPLETED' | 'SKIPPED';

export interface Group {
  id: string;
  name: string;
  description?: string;
}

export interface GroupRole {
  groupId: string;
  groupName: string;
  isLeader: boolean;
}

export interface Staff {
  id: string;
  name: string;
  idCard: string; // 新增：用于登录
  avatar: string;
  status: StaffStatus; 
  roles: GroupRole[];
  phone?: string;
  joinDate: string;
  // Talent Pool Fields
  isTalent?: boolean;
  talentNotes?: string;
}

export interface AttendanceConfig {
  startTime: string; // e.g., "09:00"
  endTime: string;   // e.g., "18:00"
  overtimeStart: string; // e.g., "19:00"
}

export interface LoginConfig {
  title: string;
  subtitle: string;
  imageUrl: string;
}

export interface PermissionSettings {
  allowLeaderExport: boolean;
  allowLeaderBroadcast: boolean;
  allowStaffViewTeam: boolean;
  showSensitiveInfo: boolean;
  enableCheckIn: boolean; // Controls global visibility of scanning/check-in features
  loginConfig?: LoginConfig;
}

export interface AttendanceRecord {
  id: string;
  staffId: string; 
  timestamp: string; 
  type: 'IN' | 'OUT';
  photoUrl?: string; 
  location?: string;
  status: 'NORMAL' | 'LATE' | 'EARLY_LEAVE' | 'OVERTIME'; 
  isManual?: boolean;
}

export interface QueueTicket {
  id: string;
  ticketNumber: string; // e.g. A001
  staffId: string;
  staffName: string;
  status: QueueStatus;
  checkInTime: string;
  calledTime?: string;
}

export interface UserSession {
  userId: string;
  role: 'ADMIN' | 'USER';
  staff?: Staff;
}

export interface InterviewQuestion {
  id: string;
  text: string;
  category: string;
  difficulty: string;
}

export interface EvaluationResult {
  score: number;
  feedback: string;
  strengths: string[];
  weaknesses: string[];
}

export interface InterviewSession {
  id: string;
  jobTitle: string;
  candidateName: string;
  date: string;
  questions: InterviewQuestion[];
  responses: Record<string, string>;
  evaluations: Record<string, EvaluationResult>;
}

export interface Announcement {
  id: string;
  title: string;
  content: string;
  date: string;
  type: 'NOTICE' | 'URGENT' | 'NEWS';
  targetGroupId?: string; // If undefined, it's global
  targetGroupName?: string;
  authorName: string;
  isSticky?: boolean; // Only admin can sticky
}

// New Registration Record Type (Legacy, kept for compatibility with existing imports)
export interface RegistrationRecord {
  id: string;
  registrationNumber: string; 
  name: string;               
  gender?: string;            
  phone?: string;             
  idCard?: string;            
  position?: string;          
  submissionTime: string;     
  dob?: string;               
  age?: string;               
  address?: string;           
  notes?: string;             
  managementNotes?: string;   
  availability?: string;      
  isTalent?: boolean;         
}

// Staff Schedule / Roster Management
export interface ScheduleRow {
  id: string;
  staffId: string; 
  name: string;    
  dob: string;     
  age: string;     
  address: string; 
  notes: string;   
  managementNotes?: string; 
  schedule: Record<string, string>; 
  isTalent?: boolean;
  talentNotes?: string;
}

export interface ScheduleData {
  headers: string[]; 
  dynamicHeaders: string[]; 
  rows: ScheduleRow[];
}

// --- NEW: Dynamic Form System Types ---

export type FormFieldType = 'TEXT' | 'NUMBER' | 'PHONE' | 'EMAIL' | 'SELECT' | 'DATE' | 'SCHEDULE' | 'SIGNATURE' | 'BANK_CARD' | 'ID_CARD' | 'GENDER' | 'ADDRESS' | 'NOTES';

export interface FormField {
  id: string;
  type: FormFieldType;
  label: string;
  placeholder?: string;
  required: boolean;
  options?: string[]; // For SELECT
  config?: any; // For SCHEDULE (e.g. available dates)
}

export interface FormTemplate {
  id: string;
  shareToken: string; // New: Permanent token for sharing
  title: string;
  description: string;
  status: 'ACTIVE' | 'CLOSED' | 'DRAFT';
  createdDate: string;
  fields: FormField[];
  submissionCount: number;
  themeColor: string; // e.g. 'blue', 'purple', 'green'
}

export interface FormSubmission {
  id: string;
  formId: string;
  submittedAt: string;
  data: Record<string, any>; // Key is field.id, Value is answer
}
]]></content>
