           <button onClick={resetForm} className="w-full py-3 rounded-xl font-bold bg-gray-100 text-gray-600 hover:bg-gray-200 transition-colors text-sm">返回</button>
        </div>
      </div>
    );
  }

  if (loginStatusView === 'WAITING_GROUP') {
    return (
      <div className="min-h-screen flex items-center justify-center bg-gray-50 font-sans p-4">
        <div className="bg-white p-8 rounded-3xl shadow-lg w-full max-w-xs border border-gray-100 animate-in zoom-in duration-300">
           <div className="w-16 h-16 bg-blue-50 rounded-full flex items-center justify-center mx-auto mb-4 text-blue-500 shadow-inner">
             <Check size={32} />
           </div>
           <h2 className="text-xl font-bold text-gray-800 mb-2 text-center">面试通过</h2>
           <p className="text-gray-400 text-sm mb-6 text-center">请等待管理员分配组别后登录。</p>
           <button onClick={resetForm} className="w-full py-3 rounded-xl font-bold bg-blue-600 text-white hover:bg-blue-700 transition-colors text-sm shadow-lg shadow-blue-200">好的</button>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen flex flex-col lg:flex-row bg-white font-sans selection:bg-indigo-100 selection:text-indigo-600">

      {/* LEFT (Desktop Only): Cover Image or Abstract Art */}
      <div className="hidden lg:block lg:w-[50%] xl:w-[60%] relative overflow-hidden bg-slate-50">
         {/* If custom image exists, show it full bleed */}
         {config.imageUrl ? (
            <>
               <img 
                  src={config.imageUrl} 
                  alt="Login Cover" 
                  className="absolute inset-0 w-full h-full object-cover animate-in fade-in duration-1000" 
               />
               <div className="absolute inset-0 bg-gradient-to-r from-black/40 via-transparent to-transparent pointer-events-none"></div>
            </>
         ) : (
            // Default Abstract Design
            <div className="absolute inset-0 bg-slate-100 flex items-center justify-center">
               <div className="absolute inset-0 opacity-20 bg-[radial-gradient(#4f46e5_1px,transparent_1px)] [background-size:20px_20px]"></div>
               <div className="w-96 h-96 bg-indigo-500/10 rounded-full blur-3xl absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 animate-pulse"></div>
               <div className="relative z-10 p-10">
                  <div className="w-64 h-80 bg-white rounded-[40px] shadow-2xl border border-gray-100 flex flex-col items-center justify-center relative overflow-hidden transform -rotate-3 hover:rotate-0 transition-transform duration-700 ease-out">
                     <div className="absolute top-0 left-0 w-full h-2 bg-indigo-500"></div>
                     <div className="flex-1 flex flex-col items-center justify-center w-full p-8 gap-4">
                        <div className="w-20 h-20 bg-indigo-50 rounded-2xl flex items-center justify-center text-indigo-600 mb-2">
                           <Check size={40} strokeWidth={3} />
                        </div>
                        <div className="w-full space-y-3">
                           <div className="h-2 w-2/3 bg-gray-100 rounded-full mx-auto"></div>
                           <div className="h-2 w-1/2 bg-gray-100 rounded-full mx-auto"></div>
                        </div>
                     </div>
                     <div className="w-full p-4 bg-gray-50 border-t border-gray-100 flex justify-center">
                        <div className="w-8 h-8 rounded-full bg-gray-200"></div>
                     </div>
                  </div>
               </div>
            </div>
         )}
      </div>

      {/* RIGHT (Mobile & Desktop): Login Form */}
      <div className="w-full lg:w-[50%] xl:w-[40%] flex items-center justify-center p-6 md:p-12 lg:p-20 bg-white relative">

        <div className="w-full max-w-sm space-y-8 animate-in slide-in-from-bottom-8 duration-700">

          {/* Header */}
          <div className="text-center space-y-4">
             {/* Logo or Default Icon */}
             <div className="flex justify-center">
                {config.logoUrl ? (
                   <img 
                     src={config.logoUrl} 
                     alt="Logo" 
                     className="h-20 w-auto object-contain transition-transform hover:scale-105" 
                   />
                ) : (
                   <div className="inline-flex items-center justify-center w-16 h-16 bg-gradient-to-br from-indigo-600 to-violet-600 text-white rounded-2xl shadow-xl shadow-indigo-200 transform hover:rotate-3 transition-transform">
                      <Zap size={28} fill="currentColor" />
                   </div>
                )}
             </div>

             <div>
                <h2 className="text-3xl font-black text-gray-900 tracking-tight">{config.title || 'STAFFTool'}</h2>
                {config.subtitle && (
                   <p className="text-gray-500 text-sm font-medium mt-2">{config.subtitle}</p>
                )}
             </div>
          </div>

          {/* Mode Switcher */}
          <div className="bg-gray-100/50 p-1 rounded-2xl flex relative">
             <button 
               onClick={() => { setLoginMode('STAFF'); setError(''); }}
               className={`flex-1 py-3 rounded-xl text-sm font-bold transition-all relative z-10 ${loginMode === 'STAFF' ? 'bg-white text-indigo-600 shadow-sm' : 'text-gray-500 hover:text-gray-700'}`}
             >
               STAFF / 编外
             </button>
             <button 
               onClick={() => { setLoginMode('ADMIN'); setError(''); }}
               className={`flex-1 py-3 rounded-xl text-sm font-bold transition-all relative z-10 ${loginMode === 'ADMIN' ? 'bg-white text-indigo-600 shadow-sm' : 'text-gray-500 hover:text-gray-700'}`}
             >
               管理后台
             </button>
          </div>

          {/* Form Fields */}
          <form onSubmit={handleLogin} className="space-y-5">

            {loginMode === 'STAFF' ? (
